	@Test
	void distinctPredicateProjectionScansPredicatePrefixesInsteadOfAllStatements(@TempDir File dataDir)
			throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			Set<IRI> expectedPredicates = new LinkedHashSet<>();
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				for (int predicateIndex = 0; predicateIndex < 4; predicateIndex++) {
					IRI predicate = VF.createIRI("urn:distinct:predicate:" + predicateIndex);
					expectedPredicates.add(predicate);
					for (int row = 0; row < 250; row++) {
						connection.add(VF.createIRI("urn:distinct:s:" + predicateIndex + ":" + row), predicate,
								VF.createIRI("urn:distinct:o:" + predicateIndex + ":" + row));
					}
				}
				connection.commit();
				store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
				LmdbPlannerAwait.awaitSketchesReady(store);

				String query = "SELECT DISTINCT ?p WHERE { ?s ?p ?o }";
				List<Value> resultPredicates = new ArrayList<>();
				try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
					while (result.hasNext()) {
						resultPredicates.add(result.next().getValue("p"));
					}
				}
				assertEquals(expectedPredicates, new LinkedHashSet<>(resultPredicates));

				Explanation explanation = connection.prepareTupleQuery(query).explain(Explanation.Level.Telemetry);
				StatementPattern pattern = firstStatementPattern((TupleExpr) explanation.tupleExpr());
				assertNotNull(pattern, explanation::toString);
				assertEquals(expectedPredicates.size(), pattern.getSourceRowsMatchedActual(), explanation::toString);
				assertTrue(pattern.getSourceRowsScannedActual() <= expectedPredicates.size() + 2L,
						"Distinct cursor skip should scan near predicate count, not statement count:\n" + explanation);
				assertTrue(
						pattern.getLongMetricActual(
								TelemetryMetricNames.DISTINCT_CURSOR_SKIP_COUNT_ACTUAL) >= expectedPredicates.size()
										- 1L,
						"Distinct cursor skip should report physical skip attempts:\n" + explanation);
				assertTrue(
						pattern.getLongMetricActual(
								TelemetryMetricNames.DISTINCT_CURSOR_SKIP_SEEK_COUNT_ACTUAL) >= expectedPredicates
										.size() - 1L,
						"Distinct cursor skip should report lower-bound seeks:\n" + explanation);
			}
		} finally {
			repository.shutDown();
		}
	}

